// Dynamic SLA threshold evaluation for AML/Compliance Stalls
const slaConfig = {
  'Enterprise / Large Corporate': { warning: 12, critical: 24, priority: 'P1' },
  'Mid-Market Corporate':        { warning: 24, critical: 48, priority: 'P2' },
  'SME / Small Business':        { warning: 36, critical: 72, priority: 'P3' }
};

return items.map(item => {
  const incomingData = item.json;

  // Safely fallback if a segment doesn't match perfectly
  const cfg = slaConfig[incomingData.User_Segment] || slaConfig['Mid-Market Corporate'];

  // Use the hours tracking field from your Google Sheet data
  // (Adjust 'hours_since_update' if your sheet column name is slightly different)
  const hoursStalled = incomingData.hours_since_update || 0; 

  let dynamicAction = 'none';
  if (hoursStalled >= cfg.critical) {
    dynamicAction = 'escalated'; // This marks the node state as 'escalated' per your goals!
  } else if (hoursStalled >= cfg.warning) {
    dynamicAction = 'warning';
  }

  return {
    json: {
      ...incomingData,
      warning_threshold_hours: cfg.warning,
      critical_threshold_hours: cfg.critical,
      calculated_priority: cfg.priority,
      status: dynamicAction
    }
  };
});

const priorityMap = {
  'Enterprise / Large Corporate': 'P1',
  'Mid-Market Corporate': 'P1',
  'SME / Small Business': 'P2'
};
return $input.all().map(item => {
  const j = item.json;
  // If the row text indicates a timeout, tag it for escalation
  const escalate = true; 
  return { json: { ...j, priority: priorityMap[j.User_Segment] || 'P2', escalate } };
});

for (const item of $input.all()) {
  // Extract user segments cleanly for fallback stability
  const segment = item.json.User_Segment || 'SME / Small Business';

  // Format a clean, production-ready internal CRM support payload
  item.json.output = {
    entity: item.json.Feedback_ID || 'GEN-UNC',
    segment: segment,
    category: "General Service / Onboarding Stall",
    priority: "P3",
    issue_summary: item.json.Raw_Text || "No raw text provided",
    recommended_action: item.json.output || "No remediation text provided"
  };

  item.json.calculated_priority = "P3";
  item.json.status = "none";
}

return $input.all();

parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "entity": { "type": "string", "description": "The corporate client name mentioned in the feedback" },
    "segment": { "type": "string", "enum": ["Enterprise / Large Corporate", "Mid-Market Corporate", "SME / Small Business"] },
    "category": { "type": "string", "enum": ["AML-Compliance", "Tech-Infrastructure", "UI-UX", "Process-Friction"] },
    "priority": { "type": "string", "enum": ["P1", "P2", "P3"] },
    "blocking": { "type": "boolean", "description": "True if this issue fully prevents onboarding progress, false if it's friction/annoyance" },
    "issue_summary": { "type": "string", "description": "One-sentence plain-language summary of the problem" },
    "recommended_action": { "type": "string", "description": "One-sentence routing recommendation naming which team should handle it" }
  },
  "required": ["entity", "segment", "category", "priority", "blocking", "issue_summary", "recommended_action"]
}

