const items = $input.all();
const rows = items.map(i => i.json);

rows.forEach(d => {
  d.simulated_age_hours = Math.floor(Math.random() * 60) + 1;
  const warning = d.warning_threshold_hours || 24;
  const critical = d.critical_threshold_hours || 48;
  d.sla_status = d.simulated_age_hours >= critical ? "🔴 CRITICAL - Breach imminent"
               : d.simulated_age_hours >= warning ? "🟠 WARNING - Approaching deadline"
               : "🟢 On track";
});

const p1 = rows.filter(d => (d.case_type || '').trim() === 'AML-Compliance');
const p2 = rows.filter(d => (d.case_type || '').trim() === 'Tech-Infrastructure');

function buildRows(list, color) {
  return list.map(d => `
    <tr>
      <td style="padding:6px; border:1px solid #eee;">${d.entity || ''}</td>
      <td style="padding:6px; border:1px solid #eee;">${d.segment || ''}</td>
      <td style="padding:6px; border:1px solid #eee;">${d.summary || ''}</td>
      <td style="padding:6px; border:1px solid #eee; font-weight:bold; color:${color};">${d.ai_remediation_summary || ''}</td>
        <td style="padding:6px; border:1px solid #eee;">${d.simulated_age_hours}h — ${d.sla_status}</td>
      </tr>`).join('');;
}

let emailBody = `
<div style="font-family: Arial, sans-serif; max-width: 700px; margin: 0 auto;">
  <div style="background:#b71c1c; color:#fff; padding:16px 20px; border-radius:6px 6px 0 0;">
    <h2 style="margin:0;">🚨 Client Feedback Escalation Digest</h2>
    <p style="margin:4px 0 0; font-size:14px;">Automated alert — ${rows.length} case(s) require action</p>
  </div>
  <div style="border:1px solid #ddd; border-top:none; padding:20px;">
`;

if (p1.length > 0) {
  emailBody += `
    <div style="margin-bottom:24px;">
      <h3 style="color:#b71c1c; border-bottom:2px solid #b71c1c; padding-bottom:6px;">
        🔴 P1 — AML/KYC Compliance (${p1.length} case${p1.length > 1 ? 's' : ''})
      </h3>
      <p style="font-size:13px; color:#444;">
        These cases carry direct regulatory and customer-trust risk. Unresolved AML/KYC verification failures can escalate to compliance breaches and client attrition. <b>Immediate action requested from AML/KYC Ops.</b>
      </p>
      <table style="width:100%; border-collapse:collapse; font-size:13px;">
        <tr style="background:#fbe9e7;">
          <th style="text-align:left; padding:6px; border:1px solid #eee;">Entity</th>
          <th style="text-align:left; padding:6px; border:1px solid #eee;">Segment</th>
          <th style="text-align:left; padding:6px; border:1px solid #eee;">Issue</th>
<th style="text-align:left; padding:6px; border:1px solid #eee;">Recommended Action</th>
          <th style="text-align:left; padding:6px; border:1px solid #eee;">SLA Status</th>
        </tr>
        ${buildRows(p1, '#b71c1c')}
      </table>
    </div>`;
}

if (p2.length > 0) {
  emailBody += `
    <div style="margin-bottom:12px;">
      <h3 style="color:#e65100; border-bottom:2px solid #e65100; padding-bottom:6px;">
        🟠 P2 — Technical Infrastructure (${p2.length} case${p2.length > 1 ? 's' : ''})
      </h3>
      <p style="font-size:13px; color:#444;">
        API/webhook timeout and system reliability issues are directly disrupting client workflows. <b>Route to DevOps/Tech Support for immediate remediation</b> to prevent further client drop-off.
      </p>
      <table style="width:100%; border-collapse:collapse; font-size:13px;">
        <tr style="background:#fff3e0;">
          <th style="text-align:left; padding:6px; border:1px solid #eee;">Entity</th>
          <th style="text-align:left; padding:6px; border:1px solid #eee;">Segment</th>
          <th style="text-align:left; padding:6px; border:1px solid #eee;">Issue</th>
 <th style="text-align:left; padding:6px; border:1px solid #eee;">Recommended Action</th>
          <th style="text-align:left; padding:6px; border:1px solid #eee;">SLA Status</th>
        </tr>
        ${buildRows(p2, '#e65100')}
      </table>
    </div>`;
}

emailBody += `
    <p style="font-size:12px; color:#888; border-top:1px solid #eee; padding-top:12px; margin-top:20px;">
      Generated automatically by the ACR (Ask–Check–Recommend) escalation engine. This digest reflects real-time classification of client feedback to minimize resolution delay and reduce customer churn risk.
    </p>
  </div>
</div>`;

return [{
  json: {
    count: rows.length,
    digest: rows,
    emailBody: emailBody
  }
}];
